<?php class Model_Mapper_EncuestaIndicador{	private static $_instance;		public static function getInstance()	{		if(null == self::$_instance)		{			self::$_instance = new self;		}		return self::$_instance;	}	private function __construct(){}	public function getIndicadoresByEncuesta($idEncuesta)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchCol($db->select()	->from(array('ei'=>'tbl_encuesta_has_tbl_indicador'),'ei.tbl_indicador_id_indicador')											->where('ei.tbl_encuesta_id_encuesta = ?',$idEncuesta)											->join(array('i'=>'tbl_indicador'),'ei.tbl_indicador_id_indicador = i.id_indicador')											->order('i.orden_indicador'));	}		public function getEncuestaByIndicador($idIndicador)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()	->from(array('ei'=>'tbl_encuesta_has_tbl_indicador'),'ei.tbl_encuesta_id_encuesta')											->where('ei.tbl_indicador_id_indicador = ?',$idIndicador));	}				public function insertEncuestaIndicador($idEncuesta,$idIndicador)	{		$fila = array(						'tbl_encuesta_id_encuesta' => $idEncuesta,						'tbl_indicador_id_indicador' => $idIndicador);		$db = Zend_Db_Table::getDefaultAdapter();		return $db->insert('tbl_encuesta_has_tbl_indicador',$fila);	}		public function updateEncuestaIndicador($idEncuesta,$idIndicador)	{		return null;	}	}